inline void negateOddsAndHalveEvens(std::vector<int>& x) {
    const std::size_t n = x.size();
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        int v = x[i];
        if ((v & 1) == 0) {          // even
            x[i] = v >> 1;          // divide by 2 (fast integer division)
