/* Compute the highest node degree in the undirected graph. The graph is defined in the adjacency
   matrix A. A is an NxN adjacency matrix stored in row-major order and represents an undirected
   graph. The function retains exactly the same semantics as the original implementation.
*/
inline int maxDegree(const std::vector<int>& A, std::size_t N) {
    int highestDegree = 0;

    // Parallel reduction to compute the maximum degree
    #pragma omp parallel for default(none) shared(A, N) reduction(max:highestDegree)
    for (std::int32_t i = 0; i < static_cast<std::int32_t>(N); ++i) {
        int degree = 0;
        std::size_t index = i * N;
        // Unroll inner loop by 4 to increase IPC
        std::size_t j = 0;
        for (; j + 3 < N; j += 4) {
            degree += A[index + j]     +
                      A[index + j + 1] +
                      A[index + j + 2] +
                      A[index + j + 3];
        }
        for (; j < N; ++j) {
            degree += A[index + j];
        }
        if (degree > highestDegree) highestDegree = degree;
    }
    return highestDegree;
}
