```cpp
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

#ifndef M_PI
#   define M_PI 3.14159265358979323846
#endif

// ---------------------------------------------------------------------
// Optimised DFT: single‑thread inner loop, parallel outer loop,
// pre‑computed twiddle factors, and local buffer reuse for speed.
// ---------------------------------------------------------------------
inline void dft(std::vector<double> const& x,
                std::vector<std::complex<double>>& output)
{
    const int N = static_cast<int>(x.size());
    output.assign(N, std::complex<double>(0.0, 0.0));

    // Pre‑compute all required complex exponentials (twiddle table)
    std::vector<std::complex<double>> twiddle(N * N);
    const double two_pi_over_N = 2.0 * M_PI / N;
    for (int n = 0; n < N; ++n) {
        for (int k = 0; k < N; ++k) {
            double ang = two_pi_over_N * n * k;
            twiddle[n * N + k] = std::complex<double>(std::cos(ang), -std::sin(ang));
        }
    }

    #pragma omp parallel for schedule(static)
    for (int k = 0; k < N; ++k) {
        std::complex<double> sum(0.0, 0.0);
        const std::complex<double>* const tbl_row = &twiddle[k]; // column k in flattened table
        for (int n = 0; n < N; ++n) {
            sum += x[n] * tbl_row[n * N];
        }
        output[k] = sum;
    }
}
