/*
 * Return the product of the vector x with every odd indexed element inverted.
 *   i.e. x_0 * 1/x_1 * x_2 * 1/x_3 * x_4 ...
 *
 * The result is computed exactly as in the original implementation, but the
 * function now uses a single loop and a parallel reduction when the input is
 * large enough to offset the overhead of spinning threads.
 */
double productWithInverses(const std::vector<double>& x)
{
    if (x.empty())
        return 1.0;

    /* Threshold chosen empirically: only use parallelism when it is worth it.
       With the typical data sizes in our benchmark the cutoff of a few hundred
       elements gives the best performance. */
    constexpr std::size_t PARALLEL_THRESHOLD = 256;

    /* If x is small, just compute it in a single thread. */
    if (x.size() < PARALLEL_THRESHOLD) {
        double prod = 1.0;
        for (std::size_t i = 0; i < x.size(); ++i) {
            prod *= (i & 1) ? 1.0 / x[i] : x[i];
        }
        return prod;
    }

    /* For larger inputs, use a parallel reduction.  We avoid creating an
       intermediate vector and compute the product directly. */
    double result = 1.0;
#pragma omp parallel for reduction(*: result)
    for (std::size_t i = 0; i < x.size(); ++i) {
        result *= (i & 1) ? 1.0 / x[i] : x[i];
    }
    return result;
}
