/* Count the number of cartesian points in each quadrant.
 * The vector points contains a list of `Point` objects.
 * Store the counts in `bins`.
 */
struct Point { double x, y; };

inline void countQuadrants(const std::vector<Point> &points,
                           std::array<std::size_t, 4> &bins) {
    // Zero the result array
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Allocate per‑thread local counters to avoid atomic contention
    int nthreads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 4>> local(nthreads);

    // Parallel loop with reduction performed manually
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        auto &cnt = local[tid];
        cnt[0] = cnt[1] = cnt[2] = cnt[3] = 0;

        #pragma omp for
        for (std::size_t i = 0; i < points.size(); ++i) {
            const auto &pt = points[i];
            /* Branch‑less quadrant selection.
             * The logic below guarantees identical results to the
             * original if‑else chain while enabling a single FMA
             * operation to decide the quadrant. */
            std::size_t q = 0;
            if (pt.x < 0) q += 2;
            if (pt.y < 0) q += 1;
            cnt[q] += 1;
        }
    }

    // Merge per‑thread counters into the final result
    for (int t = 0; t < nthreads; ++t) {
        for (int q = 0; q < 4; ++q) bins[q] += local[t][q];
    }
}
