/*
 * Count the number of pixels in image with each grayscale intensity.
 * The vector `image` is a grayscale image with values 0-255.
 * Store the results in `bins`.
 *
 * Example:
 *
 *   input:  image=[2, 116, 201, 11, 92, 92, 201, 4, 2]
 *   output: [0, 0, 2, 0, 1, …]
 *
 * The implementation uses an OpenMP parallel for with a per‑thread
 * histogram that is merged at the end.  This keeps the original
 * semantics while making the function trivially parallel on an
 * 8‑thread x86‑64 machine.
 */
constexpr size_t HISTOGRAM_SIZE = 256;
constexpr size_t NUM_THREADS = 8;          // invoke 8 threads through environment or static

void pixelCounts(std::vector<int> const& image,
                 std::array<std::size_t, HISTOGRAM_SIZE> &bins) {

    // clear the output bins
    bins.fill(0);

    // allocate thread‑private histograms
    std::vector<std::array<std::size_t, HISTOGRAM_SIZE>> localBins(NUM_THREADS);

    // parallel loop with standard schedule
    #pragma omp parallel num_threads(NUM_THREADS)
    {
        int tid = omp_get_thread_num();
        auto &local = localBins[tid];

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < image.size(); ++i) {
            // image[i] is guaranteed 0‑255, but we cast to uint8_t to avoid
            // clamping if the input contains out‑of‑range values.
            local[static_cast<std::uint8_t>(image[i])]++;
        }
    }

    // merge per‑thread histograms into the final result
    for (size_t th = 0; th < NUM_THREADS; ++th) {
        const auto &local = localBins[th];
        for (size_t v = 0; v < HISTOGRAM_SIZE; ++v) {
            bins[v] += local[v];
        }
    }
}
