//----------------------------------------------------------------------------
/*  Optimised componentCount.
 *  ------------------------------------------------------------------------ */

static inline void buildAdjacency(const std::vector<int> &A, size_t N,
                                  std::vector<std::vector<int>> &adj) {
    adj.assign(N, {});
    // Count edges first to reserve space (optional optimisation)
    std::vector<size_t> deg(N, 0);
    for (size_t i = 0; i < N; ++i)
        for (size_t j = 0; j < N; ++j)
            if (A[i * N + j]) ++deg[i];

    for (size_t i = 0; i < N; ++i) adj[i].reserve(deg[i]);

    for (size_t i = 0; i < N; ++i)
        for (size_t j = 0; j < N; ++j)
            if (A[i * N + j])
                adj[i].push_back(static_cast<int>(j));
}

//----------------------------------------------------------------------------
int componentCount(const std::vector<int> &A, size_t N) {
    if (N == 0) return 0;

    std::vector<std::vector<int>> adjacency;
    buildAdjacency(A, N, adjacency);

    std::vector<char> visited(N, 0);   // char is faster than bool on many CPUs
    int components = 0;
    std::stack<int> st;

    for (int v = 0; v < static_cast<int>(N); ++v) {
        if (visited[v]) continue;
        ++components;
        st.push(v);
        visited[v] = 1;

        while (!st.empty()) {
            int u = st.top();
            st.pop();
            for (int nei : adjacency[u]) {
                if (!visited[nei]) {
                    visited[nei] = 1;
                    st.push(nei);
                }
            }
        }
    }
    return components;
}
