#pragma once
#include <vector>
#include <unordered_map>
#include <utility>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Compute the matrix multiplication Y = A * X.
   A : sparse MxK matrix in COO format.
   X : sparse KxN matrix in COO format.
   Y : dense MxN matrix in row‑major order, pre‑allocated by the caller. */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double>& Y,
          size_t M, size_t K, size_t N)
{
    /* Initialise Y to zero */
    Y.assign(M * N, 0.0);

    /* Build a row‑based bucket for X to avoid double iteration over whole X. */
    std::vector<std::vector<std::pair<size_t, double>>> X_by_row(K);
    for (auto const& x : X) {
        X_by_row[x.row].emplace_back(x.column, x.value);
    }

#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < A.size(); ++i) {
        const auto& a = A[i];
        const auto& bucket = X_by_row[a.column];
        for (auto const& [x_col, x_val] : bucket) {
            size_t idx = a.row * N + x_col;
            double prod = a.value * x_val;
#pragma omp atomic
            Y[idx] += prod;
        }
    }
}
