```cpp
#pragma once
#include <vector>
#include <limits>
#include <cstddef>

/* Return the length of the shortest path from source to dest in the undirected graph
   defined by the adjacency matrix A (row‑major, N × N).  The graph is guaranteed
   to be connected, undirected and unweighted.  The function retains the exact
   semantics of the original implementation but is rewritten for maximal speed
   on a modern x86‑64 machine. */
inline int shortestPathLength(std::vector<int> const& A, std::size_t N,
                               int source, int dest)
{
    // Use a packed byte array for visited flags (1 byte per vertex)
    std::vector<char> visited(N, 0);
    // Allocate a statically sized queue of vertex indices
    std::vector<int> queue(N);
    int front = 0, back = 0;

    visited[source] = 1;
    queue[back++] = source * (N + 1);   // store vertex & distance packed in one int

    while (front < back) {
        int packed = queue[front++];
        int current = packed / (N + 1);
        int dist    = packed % (N + 1);

        if (current == dest) {
            return dist;
        }

        // Inline the inner loop for maximum register pressure
        const int base = current * static_cast<int>(N);
        for (int i = 0; i < static_cast<int>(N); ++i) {
            if (A[base + i] && !visited[i]) {
                visited[i] = 1;
                queue[back++] = i * (N + 1) + (dist + 1);
            }
        }
    }

    // As per the original contract, return a sentinel value if unreachable
    return std::numeric_limits<int>::max();
}
```
This version eliminates the generic `std::queue` and pair overhead, uses a flat memory layout for both adjacency data and the BFS frontier, and packs the vertex index and distance into a single 32‑bit integer to dodge extra array accesses. All operations are strictly sequential, so there is no need for OpenMP, but the code remains fully deterministic and side‑effect free, matching the original behavior exactly.

