/* Return the distance between the closest two points in the vector points. */
double closestPair(std::vector<Point> const& points) {
    const std::size_t n = points.size();
    if (n < 2) {
        return 0.0;
    }

    double minSq = std::numeric_limits<double>::max();

#pragma omp parallel for schedule(static) reduction(min:minSq)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(n) - 1; ++i) {
        const Point& pi = points[i];
        for (std::size_t j = i + 1; j < n; ++j) {
            double d = squaredDist(pi, points[j]);
            if (d < minSq) {
                minSq = d;
            }
        }
    }
    return std::sqrt(minSq);
}
