inline double distance(double a, double b) noexcept { return std::fabs(a - b); }

/* Return the distance between the closest two elements in the vector `x`.
   Example:
   input: [7, 3, 9, 12, 31, 1]
   output: 2
*/
inline double closestPair(std::vector<double> const& x) {
    constexpr size_t min_expected_size = 2;
    if (x.size() < min_expected_size) return 0.0;

    // Work on a copy to avoid modifying the original vector
    std::vector<double> tmp(x);
    std::sort(tmp.begin(), tmp.end());        // O(n log n)

    double minDist = std::numeric_limits<double>::max();
    for (size_t i = 1; i < tmp.size(); ++i) {
        const double d = distance(tmp[i], tmp[i - 1]); // adjacent give minimal
        if (d < minDist) minDist = d;                  // O(n)
        if (minDist == 0.0) break;                     // can't get better
    }
    return minDist;
