struct Element {
    std::size_t index;
    double       value;
};

/* Compute z = alpha*x + y where x and y are sparse vectors.
 * The result is accumulated into the pre‑initialised array z.
 */
inline void sparseAxpy(double alpha,
                       const std::vector<Element> &x,
                       const std::vector<Element> &y,
                       std::vector<double> &z)
{
    const Element *px = x.data();
    const Element *py = y.data();
    const Element *px_end = px + x.size();
    const Element *py_end = py + y.size();

    double *pz = z.data();

    std::size_t xi = 0, yi = 0;

    /* Main merge loop with 2‑cycle unrolling */
    while (px + 2 <= px_end && py + 2 <= py_end) {
        // Process first pair
        if (px->index < py->index) {
            pz[px->index] += alpha * px->value;
            ++px; ++xi;
        } else if (px->index > py->index) {
            pz[py->index] += py->value;
            ++py; ++yi;
        } else {
            pz[px->index] += alpha * px->value + py->value;
            ++px; ++py; ++xi; ++yi;
        }

        // Process second pair
        if (px->index < py->index) {
            pz[px->index] += alpha * px->value;
            ++px; ++xi;
        } else if (px->index > py->index) {
            pz[py->index] += py->value;
            ++py; ++yi;
        } else {
            pz[px->index] += alpha * px->value + py->value;
            ++px; ++py; ++xi; ++yi;
        }
    }

    /* Handle remaining elements of x */
    while (px < px_end) {
        pz[px->index] += alpha * px->value;
        ++px; ++xi;
    }

    /* Handle remaining elements of y */
    while (py < py_end) {
        pz[py->index] += py->value;
        ++py; ++yi;
    }
}
