#include <omp.h>

struct UnionFind {
    std::vector<int> parent;
    std::vector<std::mutex> locks;

    UnionFind(size_t n) : parent(n), locks(n) {
        std::iota(parent.begin(), parent.end(), 0);
    }

    int find(int x) {
        while (parent[x] != x) {
            int p = parent[x];
            int gp = parent[p];
            if (gp != p) parent[x] = gp; // simple path halving
            x = p;
        }
        return x;
    }

    void unite(int a, int b) {
        // lock in ascending order to avoid deadlock
        if (a == b) return;
        if (a > b) std::swap(a, b);
        std::unique_lock<std::mutex> lk1(locks[a]);
        std::unique_lock<std::mutex> lk2(locks[b]);

        int ra = find(a);
        int rb = find(b);
        if (ra == rb) return;
        parent[rb] = ra;
    }
};

int largestComponent(std::vector<int> const& A, size_t N) {
    UnionFind uf(N);

    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i) {
        for (size_t j = i + 1; j < N; ++j) {
            if (static_cast<unsigned long long>(A[i * N + j]) == 1ULL)
                uf.unite(static_cast<int>(i), static_cast<int>(j));
        }
    }

    std::vector<int> size(N, 0);
    int maxSize = 0;
    for (size_t i = 0; i < N; ++i) {
        int r = uf.find(static_cast<int>(i));
        int sz = ++size[r];
        if (sz > maxSize) maxSize = sz;
    }
    return maxSize;
}
