/* Return the logical XOR reduction of the vector of bools x.
   Example:
   input: [false, false, false, true]
   output: true
*/
inline bool reduceLogicalXOR(std::vector<bool> const& x) {
    const std::size_t n = x.size();

    // Use a 64‑bit accumulator to reduce memory traffic.
    uint64_t acc = 0;

    // Process in 64‑bit chunks using OpenMP parallel reduction.
    #pragma omp parallel for reduction(^:acc) schedule(static)
    for (std::size_t i = 0; i + 63 < n; i += 64) {
        uint64_t chunk = 0;
        // Load 64 bits into a 64‑bit word.
        for (int j = 0; j < 64; ++j) {
            if (x[i + j]) {
                chunk |= uint64_t{1} << j;
            }
        }
        acc ^= chunk;
    }

    // Handle any remaining bits ( < 64 ).
    uint64_t rem = 0;
    for (std::size_t i = (n / 64) * 64; i < n; ++i) {
        if (x[i]) {
            rem ^= uint64_t{1} << (i % 64);
        }
    }
    acc ^= rem;

    // The XOR of all bits: true iff an odd number of trues were present.
    // We can test any bit of acc (e.g., the least significant) for the result.
    return static_cast<bool>(acc & 1);
}
