#pragma once
#include <vector>
#include <cstdint>
#include <omp.h>

/* Compute the inclusive prefix sum of the vector `x` into `output`.
   The output has the same size as the input.  The implementation
   runs a fast 2‑pass parallel scan that keeps the exact semantics
   of std::inclusive_scan (the first element in `output` is
   `x[0]`).
 */
void prefixSum(const std::vector<int64_t> &x, std::vector<int64_t> &output) {
    size_t n = x.size();
    if (n == 0) return;

    output.resize(n);

    /* Determine the number of threads to use.  The compiler flag
       –fopenmp provides a runtime implementation that will select
       the optimal number of threads for the system.  The value of
       `max_threads` directly affects the granularity of the
       computation. */
    int max_threads = omp_get_max_threads();
    int block = (n + max_threads - 1) / max_threads;

    /* Temporary array to store the sum of each block.  The array
       size is one element larger than the number of blocks to hold
       the prefix sums of the block sums. */
    std::vector<int64_t> block_sums(max_threads + 1, 0);

    /* Phase 1: each thread scans its block independently and
       records the total sum of that block.  The extra element in
       `block_sums` is left zero to facilitate the exclusive scan
       in the next phase. */
#pragma omp parallel
    {
        int tid = omp_get_thread_num();
        size_t start = size_t(tid) * block;
        size_t end   = std::min(start + block, n);

        if (start < end) {
            // inclusive scan for the block
            int64_t sum = 0;
            for (size_t i = start; i < end; ++i) {
                sum += x[i];
                output[i] = sum;
            }
            block_sums[tid + 1] = sum;
        }
    }

    /* Phase 2: exclusive scan of the block sums.  The result is
       the offset that each block must add to its local results.
       This is effectively a simple prefix sum over the block sums
       array. */
    for (int i = 0; i < max_threads; ++i) {
        block_sums[i + 1] += block_sums[i];
    }

    /* Phase 3: each thread adds the offset of its block to all
       elements in that block.  The first block (tid==0) receives
       offset 0, the second block receives the sum of the first
       block, etc. */
#pragma omp parallel
    {
        int tid = omp_get_thread_num();
        size_t start = size_t(tid) * block;
        size_t end   = std::min(start + block, n);
        int64_t offset = block_sums[tid];

        for (size_t i = start; i < end; ++i) {
            output[i] += offset;
        }
    }
}
