struct Point {
    double x, y;
};

static inline double triArea(const Point& a, const Point& b, const Point& c) {
    // cross product of (b - a) and (c - a) / 2
    double cross = (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
    return 0.5 * std::abs(cross);
}

/// Return the area of the smallest triangle that can be formed by any 3 points.
double smallestArea(const std::vector<Point>& points) {
    const size_t n = points.size();
    if (n < 3) return 0.0;

    double minArea = std::numeric_limits<double>::max();

    // Parallel outer loop – each thread owns a block of i indices.
    #pragma omp parallel for schedule(static) reduction(min:minArea)
    for (size_t i = 0; i < n - 2; ++i) {
        const Point& a = points[i];
        for (size_t j = i + 1; j < n - 1; ++j) {
            const Point& b = points[j];
            // pre‑compute differences for this pair
            const double dx_ab = b.x - a.x;
            const double dy_ab = b.y - a.y;
            for (size_t k = j + 1; k < n; ++k) {
                const Point& c = points[k];
                double cross = dx_ab * (c.y - a.y) - dy_ab * (c.x - a.x);
                double area  = 0.5 * std::abs(cross);
                if (area < minArea) {
                    minArea = area;
                }
            }
        }
    }
    return minArea;
}
