    // the main sparse multiply-add loop
    const COOElement *a_ptr = A.data();
    const std::size_t a_len = A.size();
    const double *x_ptr = x.data();

    for (std::size_t k = 0; k < a_len; ++k) {
        const std::size_t r = a_ptr[k].row;
        const std::size_t c = a_ptr[k].column;
        if (r < M && c < N) {
            y_ptr[r] += alpha * a_ptr[k].value * x_ptr[c];
        }
    }
