/*
 * Replace the i‑th element of the vector x with the minimum value
 * from indices 0 through i.
 *
 * This implementation uses a two‑step parallel prefix‑minimum
 * algorithm to avoid the sequential dependency while preserving
 * the exact behaviour of `std::inclusive_scan` with a minimum
 * reduction.
 */
inline void partialMinimums(std::vector<float> &x) {
    const std::size_t N = x.size();
    if (N == 0) return;

    /* Determine the number of threads that will be used.
     * `omp_get_max_threads()` returns at most 8 in the target environment. */
    const int n_threads = std::max(1, omp_get_max_threads());
    const std::size_t stride = (N + n_threads - 1) / n_threads;

    /* 1. Each thread calculates the prefix-minimum for its block.   *
     *    The result is stored in `block_min[i]` which holds the
     *    minimum value of the block starting at index `i * stride`. */

    std::vector<float> block_min(n_threads);
    #pragma omp parallel num_threads(n_threads)
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * stride;
        const std::size_t end   = std::min(start + stride, N);

        if (start < end) {
            float cur = x[start];
            block_min[tid] = cur;
            for (std::size_t i = start + 1; i < end; ++i) {
                cur = std::min(cur, x[i]);
                x[i] = cur;          // write partial minimum locally
            }
        } else {
            block_min[tid] = std::numeric_limits<float>::max();
        }
    }

    /* 2. Compute the running minimum of the block minima. This is
     *    a sequential scan because the number of blocks is small
     *    (< 8 for the target hardware). */
    std::vector<float> prefix_min(n_threads);
    float acc = std::numeric_limits<float>::max();
    for (int i = 0; i < n_threads; ++i) {
        acc = std::min(acc, block_min[i]);
        prefix_min[i] = acc;
    }

    /* 3. Each thread updates its block with the minimum from all
     *    preceding blocks. */
    #pragma omp parallel num_threads(n_threads)
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * stride;
        const std::size_t end   = std::min(start + stride, N);

        if (tid > 0 && prefix_min[tid - 1] != std::numeric_limits<float>::max()) {
            const float add_min = prefix_min[tid - 1];
            for (std::size_t i = start; i < end; ++i) {
                x[i] = std::min(add_min, x[i]);
            }
        }
    }
}
