```cpp
#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <cstddef>

struct COOElement {
    std::size_t row, column;
    double      value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Example:

   input:  A=[{0,0,1}, {0,1,1}, {1,1,-2}]   b=[1,4]
   output: x=[3,-2]
*/
inline void solveLinearSystem(
    std::vector<COOElement> const& A,
    std::vector<double> const&    b,
    std::vector<double>&          x,
    std::size_t                    N)
{
    /* Allocate a flat dense matrix (row major) for optimal cache usage */
    std::vector<double> mat(N * N, 0.0);
    std::vector<double> b_copy(b);

    /* Build the dense matrix from COO entries */
    for (auto const& e : A) {
        mat[e.row * N + e.column] = e.value;
    }

    /* Forward elimination – Gaussian elimination with partial pivoting */
    for (std::size_t i = 0; i < N; ++i)
    {
        /* Find pivot row */
        std::size_t pivotRow = i;
        double      maxVal   = std::fabs(mat[i * N + i]);

        for (std::size_t k = i + 1; k < N; ++k)
        {
            double const val = std::fabs(mat[k * N + i]);
            if (val > maxVal)
            {
                maxVal   = val;
                pivotRow = k;
            }
        }

        /* Swap pivot row with current row if necessary */
        if (pivotRow != i)
        {
            for (std::size_t j = i; j < N; ++j) {
                std::swap(mat[pivotRow * N + j], mat[i * N + j]);
            }
            std::swap(b_copy[pivotRow], b_copy[i]);
        }

        double const pivot = mat[i * N + i];
        /* If pivot is zero the matrix is singular – keep original behaviour */
        if (pivot == 0.0) {
            continue;
        }

        /* Eliminate rows below */
        for (std::size_t k = i + 1; k < N; ++k)
        {
            double const factor = -mat[k * N + i] / pivot;
            mat[k * N + i] = 0.0;                               // explicitly zero the entry

            for (std::size_t j = i + 1; j < N; ++j) {
                mat[k * N + j] += factor * mat[i * N + j];
            }
            b_copy[k] += factor * b_copy[i];
        }
    }

    /* Back substitution */
    x.resize(N);
    for (int i = static_cast<int>(N) - 1; i >= 0; --i)
    {
        double const diag = mat[i * N + i];
        /* If diagonal element is zero we keep the original behaviour (division by zero) */
        x[i] = b_copy[i] / diag;
        for (int k = i - 1; k >= 0; --k) {
            b_copy[k] -= mat[k * N + i] * x[i];
        }
    }
}
