/* Find the k-th smallest element of the vector x.
   Example:

   input: x=[1, 7, 6, 0, 2, 2, 10, 6], k=4
   output: 6
*/
int findKthSmallest(std::vector<int> const& x, int k) {
    // Make a mutable copy because nth_element modifies the container
    std::vector<int> x_copy = x;
    // nth_element places the element that would be at position k-1
    // in sorted order at that position; all elements before it are
    // <= it, and all after it are >= it.  This is O(n) average time.
    std::nth_element(x_copy.begin(), x_copy.begin() + (k - 1), x_copy.end());
    return x_copy[k - 1];
}
