                 const std::vector<double> &B,
                 std::vector<double>       &C,
                 size_t M, size_t K, size_t N)
{
    constexpr size_t blockSize = 64;          // tuned for 8‑thread AVX2 L2 cache

    /* Parallel over outermost loop (rows of A). */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < M; ++i) {
        double *cRow = &C[i * N];
        const double *aRow = &A[i * K];

        /* Blocked accumulation over K dimension. */
        for (size_t kk = 0; kk < K; kk += blockSize) {
            size_t kEnd = std::min(kk + blockSize, K);

            /* Unrolled inner product between A(i, kk:kEnd-1) and columns of B. */
            for (size_t j = 0; j < N; ++j) {
                double sum = 0.0;
                const double *bCol = &B[kk * N + j];
                for (size_t k = kk; k < kEnd; ++k) {
                    sum += aRow[k] * bCol[(k - kk)];
                }
                cRow[j] += sum;
            }
        }
    }
}
