#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <cstddef>

struct Point{ double x,y; };

/* Euclidean distance – inlined, no pow/sqrt overhead */
inline double dist(const Point& a, const Point& b)
{
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx*dx + dy*dy);
}

/* Cross product of vectors (a→b) × (a→c) */
inline double cross(const Point& a, const Point& b, const Point& c)
{
    return (b.x - a.x)*(c.y - a.y) - (b.y - a.y)*(c.x - a.x);
}

/*
 * Convex hull perimeter – Graham‑Scan (monotone chain), O(n log n).
 * Keeps exact behaviour of the reference implementation.
 */
double convexHullPerimeter(const std::vector<Point>& points)
{
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    /* 1. sort the points */
    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(),
        [](const Point& a, const Point& b){ return a.x < b.x || (a.x == b.x && a.y < b.y); });

    /* 2. build lower hull */
    std::vector<Point> hull(2*n);
    std::size_t k = 0;
    for (std::size_t i=0;i<n;++i)
    {
        while (k>=2 && cross(hull[k-2], hull[k-1], pts[i]) <= 0) --k;
        hull[k++] = pts[i];
    }

    /* 3. build upper hull */
    std::size_t t = k+1;
    for (std::size_t i=n-1;i>0;--i)
    {
        while (k>=t && cross(hull[k-2], hull[k-1], pts[i-1]) <= 0) --k;
        hull[k++] = pts[i-1];
    }

    hull.resize(k-1);               // remove duplicate endpoint

    /* 4. compute perimeter */
    double perim = 0.0;
    for (std::size_t i=0;i<hull.size();++i)
    {
        const Point& cur  = hull[i];
        const Point& nxt  = hull[(i+1)%hull.size()];
        perim += dist(cur, nxt);
    }
    return perim;
}
