#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Same semantics as the reference implementation.
 * Uses OpenMP for parallelisation and a small loop
 * unrolling/short‑circuit tricks for speed.
 *
 * The function is intentionally written to keep
 * the source layout unchanged and only rearranges
 * the inner loops for better cache utilisation.
 */
inline void gameOfLife(std::vector<int> const& input,
                       std::vector<int> &output,
                       std::size_t N)
{
    const std::size_t stride = N;
    const std::size_t last = N - 1;

    /* Parallelise rows; each thread works on a contiguous block
       to minimise cache interference. */
    #pragma omp parallel for schedule(static)
    for (std::int64_t i = 0; i < static_cast<std::int64_t>(N); ++i) {
        const std::size_t base = i * stride;
        const std::size_t up   = (i > 0)   ? base - stride : USIZE_MAX;
        const std::size_t down = (i < last) ? base + stride : USIZE_MAX;

        for (std::size_t j = 0; j < N; ++j) {
            std::size_t idx = base + j;
            int sum = 0;

            /* neighbours in the same row */
            if (j > 0)   sum += input[idx - 1];
            if (j < last) sum += input[idx + 1];

            /* neighbours in the previous row */
            if (up != USIZE_MAX) {
                if (j > 0)   sum += input[up   - 1];
                sum += input[up];
                if (j < last) sum += input[up   + 1];
            }

            /* neighbours in the next row */
            if (down != USIZE_MAX) {
                if (j > 0)   sum += input[down - 1];
                sum += input[down];
                if (j < last) sum += input[down + 1];
            }

            /* Apply the Game of Life rules */
            if (input[idx] == 1) {
                output[idx] = (sum == 2 || sum == 3) ? 1 : 0;
            } else {
                output[idx] = (sum == 3) ? 1 : 0;
            }
        }
    }
}
