#pragma once
#include <vector>

struct COOElement {
   size_t row, column;
   double value;
};

/*
 * Perform a dense LU factorisation of a sparse matrix A, returning L and U in
 * column‑major order (row * N + col index). Unused entries are zero, while
 * the diagonal of L is always 1.  The implementation uses contiguous
 * buffers and simple *-aware loops for maximum throughput.
 *
 * Parameters
 *  - A : vector of non‑zero entries in COO format
 *  - L : output vector (size N*N) to receive the lower triangular matrix
 *  - U : output vector (size N*N) to receive the upper triangular matrix
 *  - N : matrix dimension
 */
void luFactorize(std::vector<COOElement> const& A,
                 std::vector<double> &L,
                 std::vector<double> &U,
                 size_t N)
{
    // Ensure output buffers are correctly sized and zeroed
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    // Build a dense representation of A for fast access
    std::vector<double> fullA(N * N, 0.0);
    for (const auto& e : A)
        fullA[e.row * N + e.column] = e.value;

    // Classic Doolittle LU factorisation
    for (size_t i = 0; i < N; ++i) {
        double *Urow = U.data() + i * N;   // pointer to current row of U
        double *Lrow = L.data() + i * N;   // pointer to current row of L

        for (size_t j = 0; j < N; ++j) {
            if (j >= i) {                 // compute U[i,j]
                double sum = 0.0;
                for (size_t k = 0; k < i; ++k)
                    sum += Lrow[k] * U[k * N + j];
                Urow[j] = fullA[i * N + j] - sum;
            }

            if (i > j) {                  // compute L[i,j]
                double sum = 0.0;
                for (size_t k = 0; k < j; ++k)
                    sum += Lrow[k] * U[k * N + j];
                Lrow[j] = (fullA[i * N + j] - sum) / U[j * N + j];
            }
        }
        Lrow[i] = 1.0;                     // unit diagonal of L
    }
}
