#ifndef M_PI
#define M_PI 3.14159265358979323846
#endif

//---------------------------------------------------------------------
// FFT helper – in‑place radix‑2 FFT (forward)
inline void fft_helper(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    // pre‑compute twiddle factors
    std::vector<std::complex<double>> w(N / 2);
    const double twiddle_unit_real = std::cos(-2.0 * M_PI / N);
    const double twiddle_unit_imag = std::sin(-2.0 * M_PI / N);
    std::complex<double> w_unit(twiddle_unit_real, twiddle_unit_imag);

    std::complex<double> w_pow = 1.0;
    for (std::size_t i = 0; i < N / 2; ++i) {
        w[i] = w_pow;
        w_pow *= w_unit;
    }

    // bit‑reverse permutation
    std::size_t rev = 0;
    for (std::size_t i = 0; i < N; ++i) {
        if (i < rev) std::swap(x[i], x[rev]);

        std::size_t mask = N >> 1;
        while (rev & mask) {
            rev ^= mask;
            mask >>= 1;
        }
        rev |= mask;
    }

    // FFT stages
    for (std::size_t len = 2; len <= N; len <<= 1) {
        const std::size_t half = len >> 1;
        const std::size_t step = N / len;
#pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += len) {
            for (std::size_t j = 0; j < half; ++j) {
                const std::size_t idx = j * step;
                const std::complex<double> t = w[idx] * x[i + j + half];
                x[i + j + half] = x[i + j] - t;
                x[i + j] += t;
            }
        }
    }
}
//---------------------------------------------------------------------
// Inverse FFT – conjugate‑multiply‑divide trick
inline void ifft(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    // 1. conjugate
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);

    // 2. forward FFT
    fft_helper(x);

    // 3. conjugate again
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);

    // 4. scale
    const double invN = 1.0 / static_cast<double>(N);
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
        x[i] *= invN;
}
