#include <omp.h>

/* LU factorisation (without pivoting).
   The result is stored in the same array A in row‑major format.
   The algorithm uses cache blocking, SIMD intrinsics via the compiler
   and OpenMP parallelism on the outer rows. */
static constexpr std::size_t BLOCK_SIZE = 32;   // tuned for L1/L2 cache

inline void luFactorize(std::vector<double> &A, std::size_t N)
{
    const std::size_t size = N * N;
    #pragma omp parallel
    {
        for (std::size_t k = 0; k < N; ++k) {
            const double invDiag = 1.0 / A[k * N + k];

            /* Panel factorisation: compute multipliers for rows i>k */
            #pragma omp for schedule(static)
            for (std::size_t i = k + 1; i < N; ++i) {
                double factor = A[i * N + k] * invDiag;
                A[i * N + k] = factor;

                /* Update the trailing sub‑matrix in blocks */
                for (std::size_t jj = k + 1; jj < N; jj += BLOCK_SIZE) {
                    const std::size_t jEnd = (jj + BLOCK_SIZE <= N) ? jj + BLOCK_SIZE : N;
                    #pragma ivdep
                    for (std::size_t j = jj; j < jEnd; ++j) {
                        A[i * N + j] -= factor * A[k * N + j];
                    }
                }
            }   // end for i
        }   // end for k
    }   // end parallel
}
