#pragma once
#include <vector>
#include <algorithm>
#include <cstddef>

struct Point {
    double x, y;
};

/* Return the convex hull of “points” in counter‑clockwise order.
   The algorithm is the classic monotone chain (O(n log n)).
   The implementation is inlined and uses only a few temporary buffers to
   keep the work small while remaining fully deterministic. */
inline double cross(const Point& a, const Point& b, const Point& c) noexcept{
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

struct PointCmp {
    bool operator()(const Point& a, const Point& b) const noexcept {
        return (a.x < b.x) || (a.x == b.x && a.y < b.y);
    }
};

void convexHull(std::vector<Point> const& points, std::vector<Point> &hull) {
    const std::size_t n = points.size();
    if (n < 3) {                      // Degenerate cases – just copy
        hull = points;
        return;
    }

    std::vector<Point> sorted(points);   // copy for sorting
    sorted.reserve(n);
    std::sort(sorted.begin(), sorted.end(), PointCmp());

    hull.clear();
    hull.reserve(2*n);           // at most 2*n points (lower + upper hull)

    // Build lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (hull.size() >= 2 &&
               cross(hull[hull.size()-2], hull[hull.size()-1], sorted[i]) <= 0)
            hull.pop_back();
        hull.push_back(sorted[i]);
    }

    // Build upper hull
    const std::size_t lowerSize = hull.size();
    for (std::size_t i = n-1; i > 0; --i) {
        while (hull.size() > lowerSize &&
               cross(hull[hull.size()-2], hull[hull.size()-1], sorted[i-1]) <= 0)
            hull.pop_back();
        hull.push_back(sorted[i-1]);
    }

    hull.pop_back();          // last point is same as first
}
