// Convolves a 3×3 edge‑finding kernel over a square NxN grayscale image.
// imageIn and imageOut are row‑major 1‑D vectors of length N*N.
// The function writes the result into imageOut and preserves the exact
// numeric behaviour of the original reference implementation.
inline void convolveKernel(std::vector<int> const& imageIn,
                           std::vector<int> &imageOut,
                           size_t N)
{
    // Ensure output buffer is sized correctly (harness guarantees this,
    // but we guard against accidental misuse).
    if (imageOut.size() < N * N) imageOut.resize(N * N);

    // Pointers for fast indexing
    const int*  in  = imageIn.data();
    int*        out = imageOut.data();
    const int   n   = static_cast<int>(N);

    #pragma omp parallel for collapse(2) schedule(static)
    for (int i = 0; i < n; ++i)
    {
        for (int j = 0; j < n; ++j)
        {
            int sum = 0;

            // Manually unroll the 3×3 kernel for a small, fixed size.
            // This removes the inner loop overhead and allows the compiler
            // to optimize the multiplication and addition chain.
            for (int ki = -1; ki <= 1; ++ki)
            {
                const int ii = i + ki;
                if (ii < 0 || ii >= n) continue;          // outside row bounds

                const int* rowIn = in + ii * n;

                for (int kj = -1; kj <= 1; ++kj)
                {
                    const int jj = j + kj;
                    if (jj < 0 || jj >= n) continue;      // outside column bounds

                    sum += rowIn[jj] * edgeKernel[ki + 1][kj + 1];
                }
            }

            // Clamp the result to [0, 255]
            if (sum < 0)          out[i * n + j] = 0;
            else if (sum > 255)   out[i * n + j] = 255;
            else                  out[i * n + j] = sum;
        }
    }
}
