static inline double pi() { return std::acos(-1.0); }

// Pre‑computed bit‑reverse table for up to 2^32 size (32‑bit indices)
// The table is generated lazily the first time it is used.
struct BitReversalTable {
    static std::vector<uint32_t> table;
    static int currentBits;

    static void ensure(int bits) {
        if (bits <= currentBits) return;
        int newSize = 1 << bits;
        table.resize(newSize);
        for (uint32_t i = 0; i < newSize; ++i) {
            uint32_t rev = 0;
            uint32_t v = i;
            for (int j = 0; j < bits; ++j) {
                rev = (rev << 1) | (v & 1u);
                v >>= 1;
            }
            table[i] = rev;
        }
        currentBits = bits;
    }
};

std::vector<uint32_t> BitReversalTable::table;
int BitReversalTable::currentBits = 0;

// In‑place radix‑2 Cooley–Tukey FFT (forward direction)
// The implementation follows the algorithm used in the reference code.
// The routine is single‑threaded but the outer loop that updates the twiddle
// factors is small; the heavy loops are explicitly parallelized with OpenMP.
static void fft_inplace(std::vector<std::complex<double>>& data) {
    const size_t N = data.size();
    const unsigned int logN = static_cast<unsigned int>(std::log2(N));

    // Bit‑reversal permutation
    BitReversalTable::ensure(logN);
    const auto& rev = BitReversalTable::table;
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        size_t j = rev[i] >> (32 - logN);
        if (j > i) std::swap(data[i], data[j]);
    }

    // Main butterfly
    double theta = pi() / static_cast<double>(N);
    std::complex<double> phi = std::exp(std::complex<double>(0., -2.0 * theta));
    std::complex<double> twiddle = 1.0;
    for (unsigned int step = 1, jump = N >> 1; step < N; step <<= 1, jump >>= 1) {
        twiddle = 1.0;                     // reset for each stage
        for (unsigned int sub = 0; sub < step; ++sub) {
            // Inner loop over butterflies in this stage
            #pragma omp parallel for schedule(static)
            for (size_t k = sub; k < N; k += 2 * step) {
                size_t idx = k + step;
                std::complex<double> t = data[k] - data[idx];
                data[k] += data[idx];
                data[idx] = t * twiddle;
            }
            twiddle *= phi;
        }
        phi = phi * phi;  // advance to next layer of twiddle factors
    }
}

// Public API – same signature as the original function
void fftConjugate(std::vector<std::complex<double>>& x) {
