/* Return true if `val` is only in one of vectors x or y.
   Return false if it is in both or neither.  */
inline bool xorContains(std::vector<int> const& x,
                        std::vector<int> const& y,
                        int val)
{
    bool foundInX = false;
    bool foundInY = false;

    /* Search `x` in parallel.  The first found occurrence sets the flag
       and subsequent iterations are short‑circuiting because the flag
       is already true.  */
    #pragma omp parallel for schedule(static, 64) reduction(||:foundInX)
    for (std::size_t i = 0; i < x.size(); ++i)
        if (x[i] == val)
            foundInX = true;

    /* Search `y` in parallel.  */
    #pragma omp parallel for schedule(static, 64) reduction(||:foundInY)
    for (std::size_t i = 0; i < y.size(); ++i)
        if (y[i] == val)
            foundInY = true;

