/* Compute one iteration of a 5-point 2D Jacobi stencil on `input`.
   Each element of `input` will be averaged with its four neighbors and stored
   in the corresponding element of `output`.
   i.e. output_{i,j} = (input_{i,j-1} + input_{i,j+1} + input_{i-1,j} +
   input_{i+1,j} + input_{i,j}) / 5
   Replace out-of-bounds indices with 0.
   `input` and `output` are NxN grids stored in row-major. */
inline void jacobi2D(std::vector<double> const& input,
                     std::vector<double>& output,
                     size_t N) noexcept
{
    const double inv5 = 0.2;               // 1/5 as a compile‑time constant
    const size_t Nsize = N * N;

    // Ensure the output vector has the expected size
    if (output.size() != Nsize) output.resize(Nsize);

    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        size_t base = i * N;                 // offset of the current row
        for (size_t j = 0; j < N; ++j)
        {
            size_t idx = base + j;           // linear index of (i,j)
            double sum = input[idx];         // center

            // vertical neighbors
            if (i > 0)           sum += input[(i - 1) * N + j];
            if (i + 1 < N)       sum += input[(i + 1) * N + j];

            // horizontal neighbors
            if (j > 0)           sum += input[idx - 1];
            if (j + 1 < N)       sum += input[idx + 1];

            output[idx] = sum * inv5;         // multiply by 0.2 instead of divide
        }
    }
}
