/**
 * Sort all non‑zero elements of `x` in ascending order while preserving
 * the position of any zeros. The algorithm uses libstdc++'s parallel
 * `sort` to accelerate the sorting step on a multi‑core CPU.
 */
inline void sortIgnoreZero(std::vector<int> &x) {
    // Reserve memory once to avoid reallocations while collecting non‑zeros.
    std::vector<int> nonZero;
    nonZero.reserve(x.size());

    // Gather all non‑zero elements.
    for (int v : x) {
        if (v != 0) nonZero.push_back(v);
    }

    // Sort the non‑zeros in parallel (OpenMP‑enabled).
    __gnu_parallel::sort(nonZero.begin(), nonZero.end());

    // Re‑insert the sorted values back into the original vector.
    std::size_t idx = 0;
    for (std::size_t i = 0; i < x.size(); ++i) {
        if (x[i] != 0) {
            x[i] = nonZero[idx++];
        }
    }
}
