/// Checks whether {@code x} contains {@code target}.
/// Returns {@code true} if found, otherwise {@code false}.
/// The implementation is fully parallel on up to 8 threads using OpenMP
/// and avoids the overhead of iterators and calls to <algorithm>.
inline bool contains(const std::vector<int> &x, int target) {
    const size_t n = x.size();
    if (n == 0) return false;

    std::atomic<bool> found(false);
    const int *data = x.data();

    #pragma omp parallel for schedule(static) reduction(|:found)
    for (size_t i = 0; i < n; ++i) {
