#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <cstdint>
#include <omp.h>

/* Compute the fast Fourier transform of the real‑valued sequence `x`.
   The real part of the result is stored in `r` and the imaginary part
   in `i`.  The size of `x` must be a power of two.
 */
inline static unsigned int reverse_bits(unsigned int x, unsigned int bits) {
    x = ((x & 0x55555555u) << 1) | ((x & 0xaaaaaaaau) >> 1);
    x = ((x & 0x33333333u) << 2) | ((x & 0xccccccccu) >> 2);
    x = ((x & 0x0f0f0f0fu) << 4) | ((x & 0xf0f0f0f0u) >> 4);
    x = ((x & 0x00ff00ffu) << 8) | ((x & 0xff00ff00u) >> 8);
    x = (x >> 16) | (x << 16);
    return x >> (32 - bits);
}

void fft(std::vector<std::complex<double>> const& x,
         std::vector<double> &r,
         std::vector<double> &i) noexcept
{
    const std::size_t N = x.size();
    if (N == 0) { r.clear(); i.clear(); return; }

    // 1.  Allocate working buffers
    std::vector<std::complex<double>> data(N);
    std::vector<std::complex<double>> twiddle(N >> 1);

    // 2.  Pre‑compute twiddle factors
    const double PI = 3.141592653589793238462643383279502884L;
    const double twiddle_factor = -2.0 * PI / static_cast<double>(N);
    for (std::size_t k = 0; k < (N >> 1); ++k) {
        double angle = twiddle_factor * static_cast<double>(k);
        twiddle[k] = std::complex<double>(std::cos(angle), std::sin(angle));
    }

    // 3.  Bit‑reversal copy
    const unsigned int bits = static_cast<unsigned int>(std::log2(static_cast<double>(N)));
    for (std::size_t idx = 0; idx < N; ++idx) {
        std::size_t rev = reverse_bits(static_cast<unsigned int>(idx), bits);
        data[rev] = x[idx];
    }

    // 4.  Cooley–Tukey radix‑2 decimation‑in‑time
    for (std::size_t len = 2; len <= N; len <<= 1) {
        const std::size_t half = len >> 1;
        // Each butterfly uses twiddle[ j * (N / len) ]
        const std::size_t step = N / len;
#pragma omp parallel for schedule(static)
        for (std::size_t group = 0; group < N; group += len) {
            for (std::size_t j = 0; j < half; ++j) {
                const std::complex<double> u = data[group + j];
                const std::complex<double> v = data[group + j + half] * twiddle[j * step];
                data[group + j]             = u + v;
                data[group + j + half]       = u - v;
            }
        }
    }

    // 5.  Split into real and imaginary parts
    r.resize(N);
    i.resize(N);
#pragma omp parallel for schedule(static)
    for (std::size_t j = 0; j < N; ++j) {
        r[j] = data[j].real();
        i[j] = data[j].imag();
    }
}
