#pragma once
#include <complex>
#include <vector>
#include <algorithm>
#include <cmath>
#include <omp.h>

/* Sort the vector x of complex numbers by their magnitude in ascending order.
   Example:

   input: [3.0-1.0i, 4.5+2.1i, 0.0-1.0i, 1.0-0.0i, 0.5+0.5i]
   output: [0.5+0.5i, 0.0-1.0i, 1.0-0.0i, 3.0-1.0i, 4.5+2.1i]
   The implementation below uses a parallel merge‑sort with OpenMP tasks
   for large vectors, falling back to std::sort for small ranges to maintain
   the same exact semantics without changing the function signature.\n */
static const std::size_t PARALLEL_BLK = 1 << 13;   // Threshold for parallel recursion

static inline double mag2(const std::complex<double>& z) noexcept
{
    return std::real(z) * std::real(z) + std::imag(z) * std::imag(z);
}

template <typename Iter>
static void parallel_merge_sort(Iter first, Iter last)
{
    const std::size_t n = std::distance(first, last);
    if (n <= 32) {               // Small range: use std::sort
        std::sort(first, last, [](const std::complex<double>& a, const std::complex<double>& b)
                  { return mag2(a) < mag2(b); });
        return;
    }

    Iter mid = first + n / 2;

    #pragma omp task shared(first, mid) if (n > PARALLEL_BLK)
    parallel_merge_sort(first, mid);

    #pragma omp task shared(mid, last) if (n > PARALLEL_BLK)
    parallel_merge_sort(mid, last);

    #pragma omp taskwait

    // Merge the two halves
    std::inplace_merge(first, mid, last, [](const std::complex<double>& a, const std::complex<double>& b)
                       { return mag2(a) < mag2(b); });
}

void sortComplexByMagnitude(std::vector<std::complex<double>>& x)
{
    if (x.size() <= 32) {
        std::sort(x.begin(), x.end(), [](const std::complex<double>& a, const std::complex<double>& b)
                  { return mag2(a) < mag2(b); });
        return;
    }

#pragma omp parallel
    {
#pragma omp single
        parallel_merge_sort(x.begin(), x.end());
    }
}
