#pragma once
#include <algorithm>
#include <numeric>
#include <vector>
#include <omp.h>

/* Parallel merge‑sort of indices */
namespace detail {
inline void merge(const std::vector<float>& x,
                  std::vector<size_t>& buf,
                  const std::vector<size_t>& left,
                  const std::vector<size_t>& right,
                  std::vector<size_t>& out) {
    size_t i = 0, j = 0, k = 0;
    while (i < left.size() && j < right.size()) {
        if (x[left[i]] <= x[right[j]]) out[k++] = left[i++];
        else                           out[k++] = right[j++];
    }
    while (i < left.size()) out[k++] = left[i++];
    while (j < right.size()) out[k++] = right[j++];
}

struct merge_sort_task {
    const std::vector<float>* x;
    std::vector<size_t>* buf;
    std::vector<size_t> indices;
    std::vector<size_t>* result;
};

void* parallel_merge_sort(void* arg) {
    auto* t = static_cast<merge_sort_task*>(arg);
    auto& idx = t->indices;
    size_t n = idx.size();
    if (n <= 1) {
        *t->result = idx;
        return nullptr;
    }
    size_t mid = n / 2;
    merge_sort_task left{t->x, t->buf, std::vector<size_t>(idx.begin(), idx.begin() + mid), nullptr};
    merge_sort_task right{t->x, t->buf, std::vector<size_t>(idx.begin() + mid, idx.end()), nullptr};

    pthread_t t1, t2;
    pthread_create(&t1, nullptr, parallel_merge_sort, &left);
    pthread_create(&t2, nullptr, parallel_merge_sort, &right);
    pthread_join(t1, nullptr);
    pthread_join(t2, nullptr);

    std::vector<size_t> temp(n);
    merge(*t->x, *t->buf, *left.result, *right.result, temp);
    *t->result = std::move(temp);
    return nullptr;
}

void parallel_sort_indices(const std::vector<float>& x,
                           std::vector<size_t>& idx,
                           std::vector<size_t>& buf) {
    merge_sort_task root{&x, &buf, std::move(idx), nullptr};
    pthread_create(nullptr, nullptr, parallel_merge_sort, &root);
    pthread_join(root.thread_id, nullptr);
    idx = std::move(*root.result);
}
} // namespace detail

/* For each value in the vector x compute its index in the sorted vector.
   Store the results in `ranks_`.  */
void ranks(std::vector<float> const& x, std::vector<size_t> &ranks_) {
    size_t n = x.size();
    if (n == 0) return;
    std::vector<size_t> indices(n);
    std::iota(indices.begin(), indices.end(), 0);
    /* Parallel merge sort on indices */
    std::vector<size_t> tmp(n);
    detail::parallel_sort_indices(x, indices, tmp);

    /* Linear scan to build ranks */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < n; ++i) {
        ranks_[indices[i]] = i;
    }
}
