```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <cstdint>
#include <omp.h>

/// Solve the linear system Ax = b for x.
/// A is an NxN matrix in row‑major order.
/// x and b contain N elements.
/// The function preserves the exact behaviour of the reference implementation.
///
/// @param A  Matrix (size N*N) in row‑major order.
/// @param b  Right‑hand side vector (size N).
/// @param x  Output vector (size N).  Must be allocated by the caller.
/// @param N  Dimension of the system.
///
void solveLinearSystem(std::vector<double> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       std::size_t N)
{
    // Local copies – we need a writable matrix for elimination
    std::vector<double> Ac(A);
    std::vector<double> bc(b);
    x.resize(N);                      // ensure output is the correct size

    /* ---------- Gaussian elimination ---------- */
    for (std::size_t i = 0; i + 1 < N; ++i) {
        double pivot = Ac[i * N + i];
        if (pivot == 0.0)           // singular or degenerate – original returns immediately
            return;
        const double invPivot = 1.0 / pivot;

        /* Parallelise the work for rows j > i.
           Each row j only uses data from the current pivot row i
           and writes to its own row – no data races.            */
#pragma omp parallel for schedule(static)
        for (std::size_t j = i + 1; j < N; ++j) {
            const double factor = Ac[j * N + i] * invPivot;
            double* const Arow   = &Ac[j * N];
            const double* const brow = &Ac[i * N];
            for (std::size_t k = i; k < N; ++k) {
                Arow[k] -= factor * brow[k];
            }
            bc[j] -= factor * bc[i];
        }
    }

    /* ---------- Back substitution ---------- */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        const double* const Arow = &Ac[i * N];
        for (std::size_t j = i + 1; j < N; ++j)
            sum += Arow[j] * x[j];
        x[i] = (bc[i] - sum) / Ac[i * N + i];
    }
}
